import{_ as a,o as e,c as d,a5 as r}from"./chunks/framework.BDsA2zRs.js";const g=JSON.parse('{"title":"ARD-0001 — V8 최적화 정렬 및 2026 아키텍처 동향 반영","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/ard-0001.md","filePath":"decision-log/ard-0001.md"}'),o={name:"decision-log/ard-0001.md"};function i(l,t,n,s,h,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="ard-0001-—-v8-최적화-정렬-및-2026-아키텍처-동향-반영" tabindex="-1">ARD-0001 — V8 최적화 정렬 및 2026 아키텍처 동향 반영 <a class="header-anchor" href="#ard-0001-—-v8-최적화-정렬-및-2026-아키텍처-동향-반영" aria-label="Permalink to &quot;ARD-0001 — V8 최적화 정렬 및 2026 아키텍처 동향 반영&quot;">​</a></h1><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>날짜</td><td>2026-03-20</td></tr><tr><td>상태</td><td>완료</td></tr><tr><td>결정자</td><td>2davi</td></tr></tbody></table><h2 id="배경" tabindex="-1">배경 <a class="header-anchor" href="#배경" aria-label="Permalink to &quot;배경&quot;">​</a></h2><p>ARD-0000의 구현이 완료된 후, 이 라이브러리가 2026년 프런트엔드 생태계에서 어떤 포지셔닝을 가져야 하는지와 구체적인 최적화 방향을 재검토하였다.</p><h2 id="검토-항목" tabindex="-1">검토 항목 <a class="header-anchor" href="#검토-항목" aria-label="Permalink to &quot;검토 항목&quot;">​</a></h2><h3 id="signals-기반-상태-관리와의-비교" tabindex="-1">Signals 기반 상태 관리와의 비교 <a class="header-anchor" href="#signals-기반-상태-관리와의-비교" aria-label="Permalink to &quot;Signals 기반 상태 관리와의 비교&quot;">​</a></h3><p>2025/2026년 프런트엔드 생태계는 Signals(<code>SolidJS</code>, Angular Signals)와 Zustand, Jotai 같은 경량 원자 스토어가 주류를 이루고 있다. Signals는 UI 컴포넌트의 가시성 또는 로컬 상태를 원시 값 수준에서 추적하고 렌더링을 최적화하는 데 탁월하다.</p><p><strong>결론:</strong> 이 라이브러리의 지향점은 다르다. 백엔드에서 내려온 깊게 중첩된 JSON DTO를 온전히 유지하면서 그 내부 프로퍼티 변화를 추적하고 HTTP 메서드를 분기하는 것은, 아키텍처적으로 Proxy 패턴이 합리적인 선택이다. 이 라이브러리는 UI 프레임워크를 대체하는 것이 아니라, <strong>백엔드와의 데이터 동기화 계층(Data Layer)</strong> 에서 동작하는 솔루션이라는 포지셔닝을 유지한다.</p><h3 id="dual-package-문제" tabindex="-1">Dual Package 문제 <a class="header-anchor" href="#dual-package-문제" aria-label="Permalink to &quot;Dual Package 문제&quot;">​</a></h3><p>CJS와 ESM 듀얼 패키지를 지원할 경우, 같은 패키지가 두 번 로드되어 두 개의 <code>BroadcastChannel</code> 인스턴스가 생성되는 <strong>Dual Package Hazard</strong> 가 발생할 수 있다. Node.js 22부터는 ESM을 <code>require()</code> 할 수 있으므로 CJS 지원의 필요성이 줄었다.</p><p><strong>결론:</strong> 빌드 결과물에 CJS 번들을 유지하되, <code>&quot;type&quot;: &quot;module&quot;</code> 선언과 <code>&quot;sideEffects&quot;: false</code> 로 소비자 환경에서 ESM이 우선 사용되도록 유도한다.</p><h2 id="결정-사항-요약" tabindex="-1">결정 사항 요약 <a class="header-anchor" href="#결정-사항-요약" aria-label="Permalink to &quot;결정 사항 요약&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>결정</th><th>문서</th></tr></thead><tbody><tr><td>IMPL-001</td><td>Dirty Checking 기반 HTTP 분기 알고리즘</td><td><a href="/rest-domain-state-manager/decision-log/impl-dirty-fields.html">상세 →</a></td></tr><tr><td>IMPL-002</td><td>Optimistic Update 롤백 메커니즘</td><td><a href="/rest-domain-state-manager/decision-log/impl-optimistic-rollback.html">상세 →</a></td></tr><tr><td>IMPL-003</td><td>Microtask 기반 브로드캐스트 배칭</td><td><a href="/rest-domain-state-manager/decision-log/impl-microtask-batching.html">상세 →</a></td></tr><tr><td>IMPL-004</td><td>소스 디렉토리 구조 재편</td><td><a href="/rest-domain-state-manager/decision-log/impl-src-layout.html">상세 →</a></td></tr><tr><td>IMPL-005</td><td>CI/CD 파이프라인 구축</td><td><a href="/rest-domain-state-manager/decision-log/impl-cicd-pipeline.html">상세 →</a></td></tr></tbody></table><h2 id="테스트-케이스-매트릭스" tabindex="-1">테스트 케이스 매트릭스 <a class="header-anchor" href="#테스트-케이스-매트릭스" aria-label="Permalink to &quot;테스트 케이스 매트릭스&quot;">​</a></h2><p>이 결정들의 검증을 위해 45개의 단위 테스트 케이스가 작성되었다. 레이어별 분류: Core(15), Domain(19), Network(4), Plugin(7). 14개 케이스는 VitePress Playground 컴포넌트와 연결되어 문서 내에서 인터랙티브하게 시연된다.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2><p>Vitest 79/79 테스트 통과. semantic-release를 통해 v0.7.0으로 NPM 배포 완료.</p>',17)])])}const u